import{_ as l,o as i,c as e,ag as n}from"./chunks/framework.BY_wD62d.js";const b=JSON.parse('{"title":"路线图","description":"","frontmatter":{"_rawMarkdown":"# 路线图\\n\\n本文档概述 OpenViking 的开发路线图。\\n\\n## 已完成功能\\n\\n### 核心基础设施\\n- 三层信息模型（L0/L1/L2）\\n- Viking URI 寻址系统\\n- 双层存储（AGFS + 向量索引）\\n- 异步/同步客户端支持\\n\\n### 资源管理\\n- 文本资源管理（Markdown、HTML、PDF）\\n- 自动 L0/L1 生成\\n- 带向量索引的语义搜索\\n- 资源关联和链接\\n\\n### 检索\\n- 基本语义搜索（`find`）\\n- 带意图分析的上下文感知搜索（`search`）\\n- 基于会话的查询扩展\\n- 重排序流水线\\n\\n### 会话管理\\n- 对话状态追踪\\n- 上下文和技能使用追踪\\n- 自动记忆提取\\n- 使用 LLM 的记忆去重\\n- 会话归档和压缩\\n\\n### 技能\\n- 技能定义和存储\\n- MCP 工具自动转换\\n- 技能搜索和检索\\n\\n### 配置\\n- 可插拔的 Embedding 提供者\\n- 可插拔的 LLM 提供者\\n- 基于 YAML 的配置\\n\\n### Server & Client 架构\\n- HTTP Server (FastAPI)\\n- Python HTTP Client\\n- API Key 认证\\n- 客户端抽象层（LocalClient / HTTPClient）\\n\\n---\\n\\n## 未来计划\\n\\n### CLI\\n- 完整的命令行界面，支持所有操作\\n- 分布式存储后端\\n\\n### 多模态支持\\n- 支持图像、视频、音频等多模态资源的智能解析和访问\\n- 多模态资源的目录存储结构\\n\\n### 上下文管理\\n- 上下文修改对上层的传导更新\\n- 支持对上下文的版本管理和回滚 (参考 git) \\n\\n### 资源节点的权限控制\\n- 支持多Agent / 多User 使用\\n- 不同角色的隔离设计\\n- 资源目录节点的访问控制和权限设计\\n\\n### 生态集成\\n- 流行 Agent 框架适配\\n- 插件系统，支持自定义组件\\n\\n欢迎在 issue 中提出建议和反馈。\\n---\\n\\n## 贡献\\n\\n我们欢迎贡献以帮助实现这些目标。请参阅 [贡献指南](contributing.md)。\\n"},"headers":[],"relativePath":"zh/about/03-roadmap.md","filePath":"zh/about/03-roadmap.md","lastUpdated":1770642735000}'),r={name:"zh/about/03-roadmap.md"};function t(o,a,h,d,u,s){return i(),e("div",null,[...a[0]||(a[0]=[n('<h1 id="路线图" tabindex="-1">路线图 <a class="header-anchor" href="#路线图" aria-label="Permalink to &quot;路线图&quot;">​</a></h1><p>本文档概述 OpenViking 的开发路线图。</p><h2 id="已完成功能" tabindex="-1">已完成功能 <a class="header-anchor" href="#已完成功能" aria-label="Permalink to &quot;已完成功能&quot;">​</a></h2><h3 id="核心基础设施" tabindex="-1">核心基础设施 <a class="header-anchor" href="#核心基础设施" aria-label="Permalink to &quot;核心基础设施&quot;">​</a></h3><ul><li>三层信息模型（L0/L1/L2）</li><li>Viking URI 寻址系统</li><li>双层存储（AGFS + 向量索引）</li><li>异步/同步客户端支持</li></ul><h3 id="资源管理" tabindex="-1">资源管理 <a class="header-anchor" href="#资源管理" aria-label="Permalink to &quot;资源管理&quot;">​</a></h3><ul><li>文本资源管理（Markdown、HTML、PDF）</li><li>自动 L0/L1 生成</li><li>带向量索引的语义搜索</li><li>资源关联和链接</li></ul><h3 id="检索" tabindex="-1">检索 <a class="header-anchor" href="#检索" aria-label="Permalink to &quot;检索&quot;">​</a></h3><ul><li>基本语义搜索（<code>find</code>）</li><li>带意图分析的上下文感知搜索（<code>search</code>）</li><li>基于会话的查询扩展</li><li>重排序流水线</li></ul><h3 id="会话管理" tabindex="-1">会话管理 <a class="header-anchor" href="#会话管理" aria-label="Permalink to &quot;会话管理&quot;">​</a></h3><ul><li>对话状态追踪</li><li>上下文和技能使用追踪</li><li>自动记忆提取</li><li>使用 LLM 的记忆去重</li><li>会话归档和压缩</li></ul><h3 id="技能" tabindex="-1">技能 <a class="header-anchor" href="#技能" aria-label="Permalink to &quot;技能&quot;">​</a></h3><ul><li>技能定义和存储</li><li>MCP 工具自动转换</li><li>技能搜索和检索</li></ul><h3 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h3><ul><li>可插拔的 Embedding 提供者</li><li>可插拔的 LLM 提供者</li><li>基于 YAML 的配置</li></ul><h3 id="server-client-架构" tabindex="-1">Server &amp; Client 架构 <a class="header-anchor" href="#server-client-架构" aria-label="Permalink to &quot;Server &amp; Client 架构&quot;">​</a></h3><ul><li>HTTP Server (FastAPI)</li><li>Python HTTP Client</li><li>API Key 认证</li><li>客户端抽象层（LocalClient / HTTPClient）</li></ul><hr><h2 id="未来计划" tabindex="-1">未来计划 <a class="header-anchor" href="#未来计划" aria-label="Permalink to &quot;未来计划&quot;">​</a></h2><h3 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h3><ul><li>完整的命令行界面，支持所有操作</li><li>分布式存储后端</li></ul><h3 id="多模态支持" tabindex="-1">多模态支持 <a class="header-anchor" href="#多模态支持" aria-label="Permalink to &quot;多模态支持&quot;">​</a></h3><ul><li>支持图像、视频、音频等多模态资源的智能解析和访问</li><li>多模态资源的目录存储结构</li></ul><h3 id="上下文管理" tabindex="-1">上下文管理 <a class="header-anchor" href="#上下文管理" aria-label="Permalink to &quot;上下文管理&quot;">​</a></h3><ul><li>上下文修改对上层的传导更新</li><li>支持对上下文的版本管理和回滚 (参考 git)</li></ul><h3 id="资源节点的权限控制" tabindex="-1">资源节点的权限控制 <a class="header-anchor" href="#资源节点的权限控制" aria-label="Permalink to &quot;资源节点的权限控制&quot;">​</a></h3><ul><li>支持多Agent / 多User 使用</li><li>不同角色的隔离设计</li><li>资源目录节点的访问控制和权限设计</li></ul><h3 id="生态集成" tabindex="-1">生态集成 <a class="header-anchor" href="#生态集成" aria-label="Permalink to &quot;生态集成&quot;">​</a></h3><ul><li>流行 Agent 框架适配</li><li>插件系统，支持自定义组件</li></ul><h2 id="欢迎在-issue-中提出建议和反馈。" tabindex="-1">欢迎在 issue 中提出建议和反馈。 <a class="header-anchor" href="#欢迎在-issue-中提出建议和反馈。" aria-label="Permalink to &quot;欢迎在 issue 中提出建议和反馈。&quot;">​</a></h2><h2 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to &quot;贡献&quot;">​</a></h2><p>我们欢迎贡献以帮助实现这些目标。请参阅 <a href="./contributing">贡献指南</a>。</p>',32)])])}const P=l(r,[["render",t]]);export{b as __pageData,P as default};
